# BAD: retrieves from all documents
def search_bad(query: str) -> list[str]:
    return vector_db.search(query, top_k=5)

# GOOD: filter by user's authorized document set
def search_good(query: str, user_id: str) -> list[str]:
    user_doc_ids = get_authorized_docs(user_id)
    return vector_db.search(
        query,
        top_k=5,
        filter={'doc_id': {'$in': user_doc_ids}},
    )

# Automated attack pipeline structure
class AutomatedRedTeam:
    def __init__(self, attacker_model, target_model, judge_model):
        self.attacker = attacker_model
        self.target = target_model
        self.judge = judge_model

    def run_campaign(
        self,
        goals: list[str],
        iterations_per_goal: int = 20,
    ) -> list[dict]:
        findings = []
        for goal in goals:
            attack_prompt = self.attacker.generate_attack(goal)
            for _ in range(iterations_per_goal):
                response = self.target.complete(attack_prompt)
                score = self.judge.score(goal, response)  # 0-10
                if score >= 8:  # success threshold
                    findings.append({
                        'goal': goal,
                        'attack': attack_prompt,
                        'response': response,
                        'score': score,
                    })
                    break
                attack_prompt = self.attacker.refine_attack(
                    goal, attack_prompt, response, score
                )
        return findings
